module RefModule (  
    input S,  
    input R,  
    input clk,  
    output reg Q  
);  

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
    if (S && ~R)  
        Q <= 1;  
    else if (~S && R)  
        Q <= 0;  
    // If S and R are both 0, maintain the state (Q remains unchanged)  
    // If S and R are both 1, maintain the state (Q remains unchanged)  
end  
endmodule
